import React, { useEffect, useRef, useState } from "react";

export default function EeshaWalkComponent({ soundType, onStop }) {
  const [bpm, setBpm] = useState("--");
  const [isFrozen, setIsFrozen] = useState(false);
  
  const engine = useRef({
    isRunning: true,
    audioCtx: null,
    lastStepTime: 0,
    currentBPM: 80,
    fastWin: [],
    slowWin: [],
    side: 0,
  });

  useEffect(() => {
    const init = async () => {
      // iOS Permission
      if (typeof DeviceMotionEvent.requestPermission === 'function') {
        const res = await DeviceMotionEvent.requestPermission();
        if (res !== 'granted') return onStop();
      }
      
      engine.current.audioCtx = new (window.AudioContext || window.webkitAudioContext)();
      window.addEventListener('devicemotion', handleMotion);
      scheduleNextBeat();
    };

    init();
    return () => {
      engine.current.isRunning = false;
      window.removeEventListener('devicemotion', handleMotion);
      if (engine.current.audioCtx) engine.current.audioCtx.close();
    };
  }, []);

  const handleMotion = (e) => {
    const acc = e.acceleration;
    if (!acc) return;
    const mag = Math.sqrt(acc.x**2 + acc.y**2 + acc.z**2);

    const { fastWin, slowWin } = engine.current;
    fastWin.push(mag);
    if (fastWin.length > 5) fastWin.shift();
    slowWin.push(mag);
    if (slowWin.length > 30) slowWin.shift();

    if (slowWin.length < 30) return;

    const fastAvg = fastWin.reduce((a, b) => a + b) / 5;
    const slowAvg = slowWin.reduce((a, b) => a + b) / 30;
    const ratio = fastAvg / (slowAvg + 0.001);

    const now = Date.now();
    if (ratio > 1.8 && (now - engine.current.lastStepTime) > 350) {
      if (engine.current.lastStepTime > 0) {
        const interval = now - engine.current.lastStepTime;
        engine.current.currentBPM = (60000 / interval) * 1.10;
        setBpm(Math.round(60000 / interval));
      }
      engine.current.lastStepTime = now;
      setIsFrozen(false);
    }
  };

  const scheduleNextBeat = () => {
    if (!engine.current.isRunning) return;

    const now = Date.now();
    const timeSinceLast = now - engine.current.lastStepTime;
    let nextInterval;

    if (engine.current.lastStepTime > 0 && timeSinceLast > 2500) {
      setIsFrozen(true);
      playClick(0, 1400); 
      nextInterval = 400; 
    } else {
      const pan = engine.current.side === 0 ? -0.6 : 0.6;
      playClick(pan, soundType === "click" ? 800 : 440);
      engine.current.side = 1 - engine.current.side;
      nextInterval = 60000 / Math.min(Math.max(engine.current.currentBPM, 40), 160);
    }

    setTimeout(scheduleNextBeat, nextInterval);
  };

  const playClick = (pan, freq) => {
    const ctx = engine.current.audioCtx;
    if (!ctx) return;
    const now = ctx.currentTime;
    const osc = ctx.createOscillator();
    const panner = ctx.createStereoPanner();
    const gain = ctx.createGain();

    osc.type = soundType === "click" ? "sine" : "square";
    osc.frequency.setValueAtTime(freq, now);
    panner.pan.setValueAtTime(pan, now);
    gain.gain.setValueAtTime(0.3, now);
    gain.gain.exponentialRampToValueAtTime(0.01, now + 0.1);

    osc.connect(panner).connect(gain).connect(ctx.destination);
    osc.start();
    osc.stop(now + 0.1);
  };

  return (
    <div className={`walk-setup ${isFrozen ? "frozen-blink" : ""}`}>
      <div className="walk-cue" style={{color: isFrozen ? 'var(--danger)' : 'var(--accent)'}}>
        {isFrozen ? "FREEZE DETECTED" : "WALKING"}
      </div>
      <div style={{fontSize: '100px', fontWeight: '800', color: 'var(--accent)'}}>
        {bpm}
      </div>
      <button className="walk-start-btn" style={{background: 'var(--danger)', marginTop: '20px'}} onClick={onStop}>
        STOP
      </button>
    </div>
  );
}
